static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    MeanReductionOverADimensionCustomTilingData tiling;

    auto *x_shape = context->GetInputShape(0);
    const uint32_t ndim = x_shape->GetDimNum();
    uint32_t batch = 1, dim1 = 1, dim2 = 1;
    // assume 3D for this simple kernel; reduce on dimension 1
    if (ndim >= 1) batch = static_cast<uint32_t>(x_shape->GetDim(0));
    if (ndim >= 2) dim1 = static_cast<uint32_t>(x_shape->GetDim(1));
    if (ndim >= 3) dim2 = static_cast<uint32_t>(x_shape->GetDim(2));

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int32_t *attr_dim = attrs->GetAttrPointer<int32_t>(0);
    // kernel only supports reduction on dim=1 for 3D input
    // (can be extended but we keep it simple)
    (void)attr_dim; // not used, we assume dim=1

    uint32_t totalOutput = batch * dim2;

    // blockDim: number of output elements roughly; clamp to reasonable range
    uint32_t blockDim = CeilDiv(totalOutput, ALIGN);
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;
    context->SetBlockDim(blockDim);

    // tileLen: each block processes a chunk of output elements.
    // We set tileLen = (totalOutput + blockDim - 1) / blockDim, but also align to ALIGN.
    uint32_t perBlock = CeilDiv(totalOutput, blockDim);
    perBlock = ((perBlock + ALIGN - 1) / ALIGN) * ALIGN;
    if (perBlock > 4096) perBlock = 4096; // keep local count moderate
    if (perBlock == 0) perBlock = 1;

    tiling.set_batch(batch);
    tiling.set_dim1(dim1);
    tiling.set_dim2(dim2);
    tiling.set_totalOutput(totalOutput);
    tiling.set_tileLen(perBlock);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspace = context->GetWorkspaceSizes(1);
    workspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

